const t={maxFlow:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Déterminez le débit volumétrique le plus élevé (mm³/s) que votre hotend peut soutenir — en augmentant progressivement le débit tout en surveillant la charge StallGuard de l'extrudeur pour détecter le moment où l'engrenage patine. Prévisualisez d'abord le plan ; le test en direct chauffe et extrude, alors préparez l'imprimante avant de lancer."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Aide"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"À propos de Débit max"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Fermer"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Comment l'utiliser"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Réglez la température de test et le diamètre de votre filament (choisissez un hotend pour préremplir)."}},{t:0,b:{t:2,i:[{t:3}],s:"Prévisualisez le plan — il affiche chaque palier de débit et la quantité de filament poussée."}},{t:0,b:{t:2,i:[{t:3}],s:"Cochez la liste de contrôle de sécurité, puis lancez le test en direct (chauffe + extrusion)."}},{t:0,b:{t:2,i:[{t:3}],s:"Lisez le débit maximal soutenu et copiez la valeur de slicer suggérée."}}],topics:{howItWorks:{title:{t:0,b:{t:2,i:[{t:3}],s:"Fonctionnement du test"}},body:{t:0,b:{t:2,i:[{t:3}],s:"L'extrudeur pousse le filament à un débit volumétrique qui augmente régulièrement. Tant que l'engrenage moleté agrippe correctement, la lecture de charge StallGuard reste stable ; dès qu'il commence à patiner, les lectures s'emballent. Le débit le plus élevé atteint avant cet emballement correspond à votre débit maximal soutenable. La montée s'arrête dès qu'un patinage est détecté, afin qu'aucun filament ne soit broyé au-delà du premier patinage."}}},stallguard:{title:{t:0,b:{t:2,i:[{t:3}],s:"Détection de patinage StallGuard"}},body:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard est une fonction des drivers TMC qui rend compte de la charge moteur. Ce test l'échantillonne de nombreuses fois par palier de débit et recherche une hausse soudaine de la dispersion (IQR) ou de la variation (CV) — la signature de l'engrenage qui perd son adhérence. Les seuils proviennent d'un profil propre à chaque driver. Remarque : sur un extrudeur TMC2209, cela utilise le chemin expérimental SG4, alors considérez la première exécution comme un calibrage."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Sécurité"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Il s'agit d'un test chaud et en mouvement qui provoque délibérément le patinage de l'extrudeur. Chargez du filament, assurez-vous que la buse est dégagée (au-dessus du plateau ou d'une zone de purge) et restez à proximité. L'exécution est refusée pendant une impression, et le chauffage est toujours coupé une fois le test terminé."}}},slicer:{title:{t:0,b:{t:2,i:[{t:3}],s:"Utiliser le résultat"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Reportez la valeur suggérée dans le « max volumetric speed » de votre slicer (par filament). La valeur prudente (80 % du maximum mesuré) constitue une limite quotidienne sûre ; la valeur équilibrée (90 %) pousse un peu plus loin. Des températures de hotend plus élevées augmentent généralement le débit atteignable."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossaire"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{flow:{term:{t:0,b:{t:2,i:[{t:3}],s:"Débit volumétrique"}},def:{t:0,b:{t:2,i:[{t:3}],s:"La quantité de plastique que le hotend fait fondre par seconde (mm³/s) — la véritable limite de vitesse pour l'impression rapide."}}},stallguard:{term:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un signal des drivers TMC qui rend compte de la charge mécanique du moteur, utilisé ici pour détecter le patinage de l'extrudeur."}}},slip:{term:{t:0,b:{t:2,i:[{t:3}],s:"Patinage"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Lorsque l'engrenage de l'extrudeur ne peut plus agripper le filament assez vite et saute — le plafond de débit."}}},meltzone:{term:{t:0,b:{t:2,i:[{t:3}],s:"Zone de fusion"}},def:{t:0,b:{t:2,i:[{t:3}],s:"La longueur chauffée du hotend ; une zone de fusion plus longue (par ex. Volcano) soutient un débit plus élevé."}}}}},params:{title:{t:0,b:{t:2,i:[{t:3}],s:"Paramètres du test"}},temperature:{t:0,b:{t:2,i:[{t:3}],s:"Température (°C)"}},filamentDiameter:{t:0,b:{t:2,i:[{t:3}],s:"Ø du filament (mm)"}},hotend:{t:0,b:{t:2,i:[{t:3}],s:"Hotend (optionnel)"}},hotendNone:{t:0,b:{t:2,i:[{t:3}],s:"— aucun —"}},hotendHint:{t:0,b:{t:2,i:[{t:3,v:"Attendu ~"},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},startFlow:{t:0,b:{t:2,i:[{t:3}],s:"Débit de départ (mm³/s)"}},endFlow:{t:0,b:{t:2,i:[{t:3}],s:"Débit de fin (mm³/s)"}},stepFlow:{t:0,b:{t:2,i:[{t:3}],s:"Pas (mm³/s)"}},samples:{t:0,b:{t:2,i:[{t:3}],s:"Échantillons / palier"}},extrudePerStep:{t:0,b:{t:2,i:[{t:3}],s:"Extrusion / palier (mm)"}},driver:{t:0,b:{t:2,i:[{t:3}],s:"Driver de l’extrudeur"}},driverDetected:{t:0,b:{t:2,i:[{t:3}],s:"détecté depuis l’imprimante"}},autoStealthchop:{t:0,b:{t:2,i:[{t:3}],s:"Activation automatique de StealthChop pour le test"}},autoStealthchopHint:{t:0,b:{t:2,i:[{t:3}],s:"TMC2209/2240 uniquement : écrit temporairement un seuil stealthchop_threshold sur l'extrudeur pour que StallGuard puisse le lire, puis le désactive après le test. Restaure printer.cfg ; redémarrage firmware requis."}}},plan:{button:{t:0,b:{t:2,i:[{t:3}],s:"Prévisualiser le plan"}},title:{t:0,b:{t:2,i:[{t:3}],s:"Montée planifiée"}},stepCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" paliers"}]}},totalExtrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm de filament"}]}},sgField:{t:0,b:{t:2,i:[{t:3,v:"Champ StallGuard : "},{t:4,k:"field"}]}},sgFieldUnknown:{t:0,b:{t:2,i:[{t:3}],s:"Aucun champ StallGuard connu pour ce driver"}},flowHead:{t:0,b:{t:2,i:[{t:3}],s:"Débit (mm³/s)"}},feedrateHead:{t:0,b:{t:2,i:[{t:3}],s:"Vitesse d'avance (mm/min)"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"Le test en direct chauffe le hotend et extrude du filament, délibérément jusqu'au point de patinage. Prévisualisation uniquement — rien ne s'exécute encore."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Avant de lancer — liste de contrôle de sécurité"}},items:[{t:0,b:{t:2,i:[{t:3}],s:"Le filament est chargé et avance librement."}},{t:0,b:{t:2,i:[{t:3}],s:"La buse est dégagée — au-dessus du plateau ou d'un bac de purge, pas dans le vide au-dessus des pièces."}},{t:0,b:{t:2,i:[{t:3}],s:"J'accepte que cela broie/fasse patiner délibérément un peu de filament."}},{t:0,b:{t:2,i:[{t:3}],s:"Je resterai auprès de l'imprimante pendant toute la durée du test."}}],ack:{t:0,b:{t:2,i:[{t:3}],s:"J'ai effectué tout ce qui précède et l'imprimante est prête"}},note:{t:0,b:{t:2,i:[{t:3}],s:"L'exécution est refusée pendant une impression ; le chauffage est coupé automatiquement à la fin."}}},run:{button:{t:0,b:{t:2,i:[{t:3}],s:"Lancer le test en direct"}},running:{t:0,b:{t:2,i:[{t:3}],s:"En cours… (chauffe + extrusion)"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Démarrer le test de débit maximal en direct ?"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"Cela chauffe le hotend à "},{t:4,k:"temp"},{t:3,v:" °C et extrude jusqu'à "},{t:4,k:"mm"},{t:3,v:" mm de filament, en augmentant le débit jusqu'à ce que l'extrudeur patine."}]}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Lancer maintenant"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Annuler"}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Refusé : l'imprimante est occupée (impression ou pause). Réessayez lorsqu'elle est inactive."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Le test a échoué."}},noSg:{t:0,b:{t:2,i:[{t:3}],s:"Aucun échantillon StallGuard n'a été lu — le résultat de patinage peut être peu fiable. Le champ SG en direct du driver doit probablement être ajusté pour ce modèle."}},progress:{t:0,b:{t:2,i:[{t:3,v:"Étape "},{t:4,k:"step"},{t:3,v:"/"},{t:4,k:"total"},{t:3,v:" — "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},starting:{t:0,b:{t:2,i:[{t:3}],s:"Chauffe / démarrage…"}},abort:{t:0,b:{t:2,i:[{t:3}],s:"Interrompre"}},cancelling:{t:0,b:{t:2,i:[{t:3}],s:"Interruption…"}},cancelled:{t:0,b:{t:2,i:[{t:3}],s:"Test interrompu — la chauffe a été coupée."}},reattached:{t:0,b:{t:2,i:[{t:3}],s:"Reconnecté : ce résultat s’est terminé pendant l’absence de la page."}},failed:{t:0,b:{t:2,i:[{t:3}],s:"Le test de débit max a échoué."}},abortNote:{t:0,b:{t:2,i:[{t:3}],s:"L’interruption coupe toujours la chauffe."}},parkNote:{t:0,b:{t:2,i:[{t:3}],s:"Avant de chauffer, l'imprimante effectue le homing (si nécessaire) et centre la buse pour une vue dégagée."}},phase:{homing:{t:0,b:{t:2,i:[{t:3}],s:"Homing de l'imprimante…"}},centering:{t:0,b:{t:2,i:[{t:3}],s:"Centrage de la buse…"}},heating:{t:0,b:{t:2,i:[{t:3}],s:"Chauffage du hotend…"}},checking:{t:0,b:{t:2,i:[{t:3}],s:"Vérification du signal StallGuard…"}},enabling:{t:0,b:{t:2,i:[{t:3}],s:"Activation de StealthChop…"}},ramp:{t:0,b:{t:2,i:[{t:3}],s:"Augmentation du débit…"}},reverting:{t:0,b:{t:2,i:[{t:3}],s:"Restauration de la configuration…"}}},step:{home:{t:0,b:{t:2,i:[{t:3}],s:"Homing"}},center:{t:0,b:{t:2,i:[{t:3}],s:"Centrage"}},heat:{t:0,b:{t:2,i:[{t:3}],s:"Chauffage"}},check:{t:0,b:{t:2,i:[{t:3}],s:"Vérification"}},ramp:{t:0,b:{t:2,i:[{t:3}],s:"Montée"}}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Résultat"}},maxFlow:{t:0,b:{t:2,i:[{t:3}],s:"Débit maximal soutenu"}},slipAt:{t:0,b:{t:2,i:[{t:3,v:"Patinage détecté à "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},noSlip:{t:0,b:{t:2,i:[{t:3}],s:"Aucun patinage jusqu'au débit le plus élevé testé"}},reason:{t:0,b:{t:2,i:[{t:3}],s:"Détail"}},recommendTitle:{t:0,b:{t:2,i:[{t:3}],s:"Valeurs de slicer suggérées (max volumetric speed)"}},conservative:{t:0,b:{t:2,i:[{t:3}],s:"Prudent (80 %)"}},balanced:{t:0,b:{t:2,i:[{t:3}],s:"Équilibré (90 %)"}},units:{t:0,b:{t:2,i:[{t:3}],s:"mm³/s"}},fromBefore:{t:0,b:{t:2,i:[{t:3,v:"Mesuré plus tôt ("},{t:4,k:"at"},{t:3,v:") — relancez pour des chiffres frais."}]}},unreliableTitle:{t:0,b:{t:2,i:[{t:3}],s:"Non fiable — aucun signal StallGuard"}},unmeasured:{t:0,b:{t:2,i:[{t:3}],s:"atteint, non confirmé"}}},states:{loadingHotends:{t:0,b:{t:2,i:[{t:3}],s:"Chargement des hotends…"}}},camera:{title:{t:0,b:{t:2,i:[{t:3}],s:"Caméra en direct"}},live:{t:0,b:{t:2,i:[{t:3}],s:"EN DIRECT"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Caméra indisponible."}},willShow:{t:0,b:{t:2,i:[{t:3}],s:"Une vue en direct de la caméra montrera la buse pendant le test."}},minimize:{t:0,b:{t:2,i:[{t:3}],s:"Réduire"}},maximize:{t:0,b:{t:2,i:[{t:3}],s:"Agrandir"}},enlarge:{t:0,b:{t:2,i:[{t:3}],s:"Élargir"}},shrink:{t:0,b:{t:2,i:[{t:3}],s:"Rétrécir"}}}}};export{t as default};
